using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface ISummarizationService
{
    string Summarize(string text, int maxSentences);
    int CountSentences(string text);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization using word-frequency sentence scoring.
/// Splits the document into sentences, ranks each sentence by the sum of
/// its word frequencies, and returns the top-N sentences in their original order.
/// </summary>
public partial class ExtractiveSummarizationService : ISummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","in","on","at","to","for",
        "of","with","by","from","as","into","about","between","through","during",
        "before","after","above","below","not","no","nor","so","if","then",
        "than","too","very","just","that","this","it","its","i","me","my",
        "we","our","you","your","he","him","his","she","her","they","them","their"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"[^\w\s]")]
    private static partial Regex PunctuationStripper();

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, i) => (Index: i, Sentence: s, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    public int CountSentences(string text) => SplitSentences(text).Length;

    private static string[] SplitSentences(string text)
    {
        return SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToArray();
    }

    private static Dictionary<string, int> BuildWordFrequencies(string[] sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = ExtractWords(sentence);
        if (words.Length == 0) return 0;

        double total = words
            .Where(w => !StopWords.Contains(w))
            .Sum(w => wordFrequencies.GetValueOrDefault(w));

        // Normalize by word count to avoid bias toward long sentences
        return total / words.Length;
    }

    private static string[] ExtractWords(string text)
    {
        return PunctuationStripper()
            .Replace(text, "")
            .Split(' ', StringSplitOptions.RemoveEmptyEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly ISummarizationService _summarizationService;

    public SummarizeController(ISummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizationService.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = _summarizationService.CountSentences(request.Text),
            SummarySentenceCount = _summarizationService.CountSentences(summary)
        });
    }
}

